class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string res;
        int cnt = 0;
        for(int i = s.length() - 1; i >= 0; i--){
            if(s[i] != '-'){
                if(cnt == k){
                    res += '-';
                    cnt = 0;
                }
                res += toupper(s[i]);
                cnt++;
            }
        }
        reverse(res.begin(), res.end());
        return res;
    }
};
```
